```typescript
interface ConfigData {
  db: {
    host: string,
    port: number,
    username: string,
    password: string,
  },
  server: {
    host: string,
    port: number,
  },
}

class Config {
  private data: ConfigData;

  constructor(data: ConfigData) {
    this.data = data;
  }

  getConfig() {
    return this.data;
  }

  getDbHost(): string {
    return this.data.db.host;
  }

  getDbUsername(): string {
    return this.data.db.username;
  }

  getServerHost(): string {
    return this.data.server.host;
  }
}

const config = new Config({
  db: {
    host: 'localhost',
    port: 5432,
    username: 'user',
    password: 'pass',
  },
  server: {
    host: 'localhost',
    port: 8080,
  },
});

console.log(config.getConfig());
```
